import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"冻霜踏地","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/冻霜踏地.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/冻霜踏地.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/冻霜踏地.md"};function _(l,e,i,p,c,b){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"冻霜踏地",tabindex:"-1"},[n("冻霜踏地 "),a("a",{class:"header-anchor",href:"#冻霜踏地","aria-label":'Permalink to "冻霜踏地"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),o('<h1 id="冻霜踏地-1" tabindex="-1">冻霜踏地 <a class="header-anchor" href="#冻霜踏地-1" aria-label="Permalink to &quot;冻霜踏地&quot;">​</a></h1><p>冻霜踏地</p><p>价格：B+2000<br> 描述：《艾尔登法环》世界中存在的能赋予武器属性，战技的战灰之一。在取得时需要选定自身持有的一个武器，将战灰赋予其上。只有在装备那个武器时，才可以使用战灰的战技。<br> 这个战灰可以附着在所有的近战武器上。<br> 一柄武器仅可以被赋予一个战灰。战灰所选定的武器可以在一次长休时进行变更。<br> 【寒冷】：战灰所附带的属性之一，每在智力上具有2点附加成功，就在附加了本战灰的武器的攻击上获得1点器械加值，并且在以附加了本战灰的武器攻击时，额外对敌人造成1点冻寒伤害。<br> 【战技：冻霜踏地】：大力踏向地面，让冻霜随之扩散的战技。<br> 以一个整轮动作，消耗3点意志，你将寒气凝结在腿部，然后重重地踏向地面。<br> 你进行一次以你附加了该战灰的武器所进行的攻击，这次攻击对30米半径的扇形范围内的所有对象生效，并且无论你原本的武器造成何种类型伤害，这次攻击所造成的伤害都为单纯的冻寒伤害。<br> 这次攻击的伤害需要以反射豁免，并且这次攻击还会附带等同于伤害数的冻结点数和具有【碾压】特性。<br> 每轮一次，你进行的本战技的攻击检定的成功数增加一半。</p><p>每一个对交界地历史有足够了解的褪色者都知道，冻霜踏地曾经因为拥有过于强大的力量而被无上意志设下了禁锢。<br> 然而，在主神的帮助下，你可以重现冻霜踏地曾经的力量。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',6)])])}const f=r(d,[["render",_]]);export{m as __pageData,f as default};
